import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';

const roles = [
  'Software Engineer',
  'Full Stack Developer',
  'Frontend Developer',
  'Backend Developer',
  'React Developer',
  'Node.js Developer'
];

const techStack = [
  { name: 'React', icon: 'react', color: '#61DAFB' },
  { name: 'Node.js', icon: 'nodejs', color: '#339933' },
  { name: 'Express', icon: 'express', color: '#FFFFFF' },
  { name: 'JavaScript', icon: 'js', color: '#F7DF1E' },
  { name: 'PHP', icon: 'php', color: '#777BB4' },
  { name: 'Laravel', icon: 'laravel', color: '#FF2D20' },
  { name: 'MySQL', icon: 'mysql', color: '#4479A1' },
  { name: 'Git', icon: 'git', color: '#F05032' },
  { name: 'GitHub', icon: 'github', color: '#FFFFFF' },
  { name: 'Bootstrap', icon: 'bootstrap', color: '#7952B3' },
  { name: 'Tailwind CSS', icon: 'tailwindcss', color: '#06B6D4' },
  { name: 'VS Code', icon: 'vscode', color: '#007ACC' },
  { name: 'Figma', icon: 'figma', color: '#F24E1E' },
  { name: 'Postman', icon: 'postman', color: '#FF6C37' }
];

export default function Home() {
  const [roleIndex, setRoleIndex] = useState(0);
  const [cursorPosition, setCursorPosition] = useState({ x: 0, y: 0 });
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setRoleIndex((prev) => (prev + 1) % roles.length);
    }, 2800);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setCursorPosition({ x: e.clientX, y: e.clientY });
      setMousePosition({ x: e.clientX / window.innerWidth, y: e.clientY / window.innerHeight });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const marqueeItems = [...techStack, ...techStack, ...techStack];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600;700&display=swap');

        :root {
          --bg-primary: #101012;
          --bg-secondary: #18181C;
          --surface: #202026;
          --accent-primary: #D10072;
          --accent-secondary: #B8005F;
          --accent-hover: #FF2E88;
          --text-primary: #F5F5F5;
          --text-secondary: #A8A8A8;
          --border-color: rgba(255,255,255,0.08);
          --glow-magenta: rgba(209,0,114,0.18);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: var(--bg-primary);
          color: var(--text-primary);
          min-height: 100vh;
          font-family: 'Inter', sans-serif;
          overflow-x: hidden;
          cursor: none;
        }

        /* Custom Cursor */
        .cursor-dot {
          position: fixed;
          width: 6px;
          height: 6px;
          border-radius: 50%;
          background: var(--accent-primary);
          pointer-events: none;
          z-index: 9999;
          transform: translate(-50%, -50%);
          transition: all 0.08s ease;
          box-shadow: 0 0 20px rgba(209,0,114,0.3);
        }

        .cursor-ring {
          position: fixed;
          width: 40px;
          height: 40px;
          border-radius: 50%;
          border: 1px solid rgba(209,0,114,0.15);
          pointer-events: none;
          z-index: 9998;
          transform: translate(-50%, -50%);
          transition: all 0.15s ease;
        }

        /* Background Layers */
        .bg-layer {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background: 
            radial-gradient(ellipse at 70% 50%, rgba(209,0,114,0.06) 0%, transparent 50%),
            radial-gradient(ellipse at 30% 80%, rgba(209,0,114,0.03) 0%, transparent 40%),
            linear-gradient(180deg, var(--bg-primary) 0%, var(--bg-secondary) 100%);
        }

        /* Leopard Texture - Ultra Subtle */
        .bg-leopard {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.025;
          background-image: 
            radial-gradient(ellipse at 15% 25%, rgba(209,0,114,0.03) 0%, transparent 5px),
            radial-gradient(ellipse at 85% 75%, rgba(209,0,114,0.02) 0%, transparent 4px),
            radial-gradient(ellipse at 45% 55%, rgba(209,0,114,0.015) 0%, transparent 3px),
            radial-gradient(ellipse at 65% 35%, rgba(209,0,114,0.01) 0%, transparent 4px);
          background-size: 180px 180px, 220px 220px, 200px 200px, 160px 160px;
          animation: leopardFloat 30s ease-in-out infinite;
        }

        @keyframes leopardFloat {
          0%, 100% { transform: scale(1) rotate(0deg); }
          50% { transform: scale(1.05) rotate(1deg); }
        }

        /* Noise Texture */
        .bg-noise {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.035;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E");
          mix-blend-mode: overlay;
        }

        .main-content {
          position: relative;
          z-index: 1;
          height: 100vh;
          display: flex;
          flex-direction: column;
          overflow: hidden;
        }

        /* Hero Section - 100vh */
        .hero-section {
          flex: 1;
          display: flex;
          align-items: center;
          padding: 0 0 2rem;
          position: relative;
          min-height: 0;
        }

        /* Profile Image - Background Element */
        .profile-wrapper {
          position: absolute;
          right: -5%;
          top: 50%;
          transform: translateY(-50%);
          width: 55%;
          height: 80%;
          pointer-events: none;
          z-index: 0;
        }

        .profile-glow {
          position: absolute;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          width: 80%;
          height: 80%;
          border-radius: 50%;
          background: radial-gradient(circle, rgba(209,0,114,0.15) 0%, transparent 70%);
          filter: blur(60px);
          animation: glowPulse 4s ease-in-out infinite;
        }

        @keyframes glowPulse {
          0%, 100% { opacity: 0.6; transform: translate(-50%, -50%) scale(1); }
          50% { opacity: 1; transform: translate(-50%, -50%) scale(1.1); }
        }

        .profile-image-container {
          position: relative;
          width: 100%;
          height: 100%;
          display: flex;
          align-items: center;
          justify-content: center;
          mask-image: radial-gradient(ellipse at center, black 50%, transparent 75%);
          -webkit-mask-image: radial-gradient(ellipse at center, black 50%, transparent 75%);
        }

        .profile-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: center;
          opacity: 0.3;
          filter: grayscale(0.5) contrast(1.1);
          transition: opacity 0.8s ease;
        }

        .profile-image:hover {
          opacity: 0.35;
        }

        /* Hero Content - Left Aligned */
        .hero-content {
          position: relative;
          z-index: 2;
          max-width: 700px;
          padding: 2rem 0;
        }

        .hero-greeting {
          font-size: 0.85rem;
          color: var(--text-secondary);
          margin-bottom: 0.75rem;
          font-weight: 400;
          letter-spacing: 2px;
          text-transform: uppercase;
          opacity: 0.7;
        }

        /* Rotating Title */
        .rotating-title-container {
          height: 3.8rem;
          overflow: hidden;
          margin-bottom: 1.25rem;
          position: relative;
        }

        .rotating-title-track {
          display: flex;
          flex-direction: column;
          animation: slideVertical 16.8s cubic-bezier(0.65, 0, 0.35, 1) infinite;
        }

        @keyframes slideVertical {
          0%, 14.28% { transform: translateY(0); }
          16.66%, 30.94% { transform: translateY(-3.8rem); }
          33.32%, 47.6% { transform: translateY(-7.6rem); }
          49.98%, 64.26% { transform: translateY(-11.4rem); }
          66.64%, 80.92% { transform: translateY(-15.2rem); }
          83.3%, 97.58% { transform: translateY(-19rem); }
          100% { transform: translateY(-22.8rem); }
        }

        .rotating-title-item {
          height: 3.8rem;
          display: flex;
          align-items: center;
          font-family: 'Space Grotesk', sans-serif;
          font-size: 2.6rem;
          font-weight: 700;
          color: var(--text-secondary);
          letter-spacing: -0.5px;
        }

        .rotating-title-item .accent-dot {
          color: var(--accent-primary);
          margin-right: 0.75rem;
          font-size: 1.8rem;
        }

        .hero-name {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 4.8rem;
          font-weight: 900;
          line-height: 1.05;
          margin-bottom: 0.75rem;
          letter-spacing: -3px;
        }

        .hero-name .highlight {
          background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .hero-description {
          font-size: 1rem;
          color: var(--text-secondary);
          max-width: 480px;
          line-height: 1.8;
          margin-bottom: 2rem;
          font-weight: 300;
        }

        .hero-actions {
          display: flex;
          align-items: center;
          gap: 1.5rem;
          flex-wrap: wrap;
          margin-bottom: 2rem;
        }

        .btn-primary {
          display: inline-flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.85rem 2.6rem;
          border-radius: 50px;
          background: var(--accent-primary);
          color: #fff;
          font-weight: 600;
          font-size: 0.9rem;
          text-decoration: none;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          border: none;
          cursor: pointer;
          position: relative;
          overflow: hidden;
          box-shadow: 0 0 40px rgba(209,0,114,0.15);
        }

        .btn-primary::before {
          content: '';
          position: absolute;
          inset: 0;
          background: linear-gradient(135deg, var(--accent-primary), var(--accent-hover));
          opacity: 0;
          transition: opacity 0.4s ease;
        }

        .btn-primary:hover {
          transform: translateY(-3px) scale(1.02);
          box-shadow: 0 20px 60px rgba(209,0,114,0.3);
        }

        .btn-primary:hover::before {
          opacity: 1;
        }

        .btn-primary span {
          position: relative;
          z-index: 1;
        }

        .btn-primary .arrow {
          display: inline-block;
          transition: transform 0.3s ease;
          position: relative;
          z-index: 1;
        }

        .btn-primary:hover .arrow {
          transform: translateX(6px);
        }

        .social-links {
          display: flex;
          gap: 0.65rem;
        }

        .social-link {
          width: 42px;
          height: 42px;
          border-radius: 50%;
          background: rgba(255,255,255,0.02);
          border: 1px solid var(--border-color);
          display: inline-flex;
          align-items: center;
          justify-content: center;
          color: var(--text-secondary);
          text-decoration: none;
          font-size: 1rem;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .social-link:hover {
          background: var(--accent-primary);
          color: #fff;
          transform: translateY(-3px);
          border-color: var(--accent-primary);
          box-shadow: 0 10px 30px rgba(209,0,114,0.2);
        }

        /* Tech Stack Marquee */
        .tech-marquee-section {
          padding: 1.2rem 0;
          border-top: 1px solid var(--border-color);
          border-bottom: 1px solid var(--border-color);
          background: var(--bg-secondary);
          position: relative;
          overflow: hidden;
          flex-shrink: 0;
        }

        .tech-marquee-track {
          display: flex;
          gap: 2.5rem;
          animation: marqueeScroll 24s linear infinite;
          width: max-content;
        }

        @keyframes marqueeScroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-33.33%); }
        }

        .tech-item {
          display: flex;
          align-items: center;
          gap: 0.7rem;
          padding: 0.4rem 1.4rem;
          background: var(--surface);
          border-radius: 50px;
          border: 1px solid var(--border-color);
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          flex-shrink: 0;
          white-space: nowrap;
          cursor: default;
        }

        .tech-item:hover {
          border-color: var(--accent-primary);
          transform: translateY(-2px);
          box-shadow: 0 10px 30px rgba(209,0,114,0.05);
        }

        .tech-icon {
          width: 22px;
          height: 22px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.1rem;
        }

        .tech-icon svg {
          width: 100%;
          height: 100%;
        }

        .tech-name {
          font-size: 0.82rem;
          font-weight: 500;
          color: var(--text-secondary);
        }

        /* View Projects Button */
        .view-projects-wrapper {
          padding: 1.5rem 0;
          text-align: center;
          background: var(--bg-primary);
          flex-shrink: 0;
        }

